        internal class UpgradeRemoveRecommendedCommands : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                // Migrate bindings from FLIP_OR_ANSWER_RECOMMENDED to FLIP_OR_ANSWER_EASE3
                // and from FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED to FLIP_OR_ANSWER_EASE4
                val recommendedKey = ViewerCommand.FLIP_OR_ANSWER_RECOMMENDED.preferenceKey
                val betterRecommendedKey = ViewerCommand.FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED.preferenceKey
                val ease3Key = ViewerCommand.FLIP_OR_ANSWER_EASE3.preferenceKey
                val ease4Key = ViewerCommand.FLIP_OR_ANSWER_EASE4.preferenceKey

                // Add FLIP_OR_ANSWER_RECOMMENDED bindings to FLIP_OR_ANSWER_EASE3
                if (preferences.contains(recommendedKey)) {
                    val recommendedBindings = MappableBinding.fromPreference(preferences, ViewerCommand.FLIP_OR_ANSWER_RECOMMENDED)
                    if (recommendedBindings.isNotEmpty()) {
                        // Add at the end to preserve FLIP_OR_ANSWER_EASE3's existing bindings
                        for (binding in recommendedBindings) {
                            ViewerCommand.FLIP_OR_ANSWER_EASE3.addBindingAtEnd(preferences, binding)
                        }
                    }
                    preferences.edit { remove(recommendedKey) }
                }

                // Add FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED bindings to FLIP_OR_ANSWER_EASE4
                if (preferences.contains(betterRecommendedKey)) {
                    val betterRecommendedBindings = MappableBinding.fromPreference(preferences, ViewerCommand.FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED)
                    if (betterRecommendedBindings.isNotEmpty()) {
                        // Add at the end to preserve FLIP_OR_ANSWER_EASE4's existing bindings
                        for (binding in betterRecommendedBindings) {
                            ViewerCommand.FLIP_OR_ANSWER_EASE4.addBindingAtEnd(preferences, binding)
                        }
                    }
                    preferences.edit { remove(betterRecommendedKey) }
                }
            }
        }
    }
}"}

